package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"
)

// Authenticator exposes the authentication operations used by HTTP handlers.
type Authenticator interface {
	CurrentUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireAdmin(r *http.Request) (*dusers.User, *HTTPError)
}

// AuthService provides a façade over the authentication helpers so callers can
// depend on a single injected object rather than package-level functions.
type AuthService struct {
	users dusers.ServiceInterface
}

// NewAuthService constructs a façade that uses the provided users service for
// token validation and password-change enforcement.
func NewAuthService(users dusers.ServiceInterface) *AuthService {
	return &AuthService{users: users}
}

// CurrentUser returns the authenticated user, ensuring any password-change
// requirements are enforced.
func (a *AuthService) CurrentUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateUserAndEnforcePasswordChangeGetUser(r, a.users)
}

// RequireUser resolves the authenticated user without checking the
// must-change-password flag.
func (a *AuthService) RequireUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateTokenAndGetUser(r, a.users)
}

// RequireAdmin ensures the current user is authenticated and has admin privileges.
func (a *AuthService) RequireAdmin(r *http.Request) (*dusers.User, *HTTPError) {
	user, err := a.CurrentUser(r)
	if err != nil {
		return nil, err
	}

	if strings.ToUpper(user.UserType) != "ADMIN" {
		return nil, &HTTPError{
			StatusCode: http.StatusForbidden,
			Message:    "admin privileges required",
		}
	}

	return user, nil
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"

	"github.com/golang-jwt/jwt/v4"
)

func Authenticate(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Here you would verify the JWT token or session
		// If it's valid, call next.ServeHTTP to pass to the next handler
		// Otherwise, return an error
	})
}

// ValidateUserAndEnforcePasswordChange performs user validation and checks if a password change is required.
// It returns the user and any errors encountered.
func ValidateUserAndEnforcePasswordChangeGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *HTTPError) {
	user, httpErr := ValidateTokenAndGetUser(r, svc)
	if httpErr != nil {
		return nil, httpErr
	}

	// Check if a password change is required
	if httpErr := CheckMustChangePasswordFlag(user); httpErr != nil {
		return nil, httpErr
	}

	return user, nil
}

// ValidateTokenAndGetUser checks that the user is who they claim to be, and returns their information for use
func ValidateTokenAndGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *HTTPError) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Authorization header is required"}
	}

	tokenString := strings.TrimPrefix(authHeader, "Bearer ")
	token, err := jwt.ParseWithClaims(tokenString, &UserClaims{}, func(token *jwt.Token) (interface{}, error) {
		return getJWTKey(), nil
	})
	if err != nil {
		return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Invalid token"}
	}

	if claims, ok := token.Claims.(*UserClaims); ok && token.Valid {
		user, err := svc.GetUser(r.Context(), claims.Username)
		if err != nil {
			if err == dusers.ErrUserNotFound {
				return nil, &HTTPError{StatusCode: http.StatusNotFound, Message: "User not found"}
			}
			return nil, &HTTPError{StatusCode: http.StatusInternalServerError, Message: "Failed to load user"}
		}
		return user, nil
	}
	return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Invalid token"}
}

// CheckMustChangePasswordFlag checks if the user needs to change their password
func CheckMustChangePasswordFlag(user *dusers.User) *HTTPError {
	if user.MustChangePassword {
		return &HTTPError{
			StatusCode: http.StatusForbidden,
			Message:    "Password change required",
		}
	}
	return nil
}

package marketshandlers

import (
	"encoding/json"
	"net/http"
	"strconv"

	"socialpredict/handlers/markets/dto"
	dmarkets "socialpredict/internal/domain/markets"

	"github.com/gorilla/mux"
)

// ProjectNewProbabilityHandler handles the projection of a new probability based on a new bet.
func ProjectNewProbabilityHandler(svc dmarkets.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// 1. Parse HTTP parameters
		vars := mux.Vars(r)
		marketIdStr := vars["marketId"]
		amountStr := vars["amount"]
		outcome := vars["outcome"]

		// Parse marketId
		marketId, err := strconv.ParseInt(marketIdStr, 10, 64)
		if err != nil {
			http.Error(w, "Invalid market ID", http.StatusBadRequest)
			return
		}

		// Parse amount
		amount, err := strconv.ParseInt(amountStr, 10, 64)
		if err != nil {
			http.Error(w, "Invalid amount value", http.StatusBadRequest)
			return
		}

		// 2. Build domain request
		projectionReq := dmarkets.ProbabilityProjectionRequest{
			MarketID: marketId,
			Amount:   amount,
			Outcome:  outcome,
		}

		// 3. Call domain service
		projection, err := svc.ProjectProbability(r.Context(), projectionReq)
		if err != nil {
			// 4. Map domain errors to HTTP status codes
			switch err {
			case dmarkets.ErrMarketNotFound:
				http.Error(w, "Market not found", http.StatusNotFound)
			case dmarkets.ErrInvalidInput:
				http.Error(w, "Invalid input parameters", http.StatusBadRequest)
			default:
				http.Error(w, "Internal server error", http.StatusInternalServerError)
			}
			return
		}

		// 5. Return response DTO
		response := dto.ProbabilityProjectionResponse{
			MarketID:             marketId,
			CurrentProbability:   projection.CurrentProbability,
			ProjectedProbability: projection.ProjectedProbability,
			Amount:               amount,
			Outcome:              outcome,
		}

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(response)
	}
}

