package markets

import (
	"context"
)

// ResolveMarket resolves a market with a given outcome.
func (s *Service) ResolveMarket(ctx context.Context, marketID int64, resolution string, username string) error {
	outcome, err := s.resolutionPolicy.NormalizeResolution(resolution)
	if err != nil {
		return err
	}

	market, err := s.repo.GetByID(ctx, marketID)
	if err != nil {
		return ErrMarketNotFound
	}
	if market == nil {
		return ErrMarketNotFound
	}

	if err := s.resolutionPolicy.ValidateResolutionRequest(market, username); err != nil {
		return err
	}

	return s.resolutionPolicy.Resolve(ctx, s.repo, s.userService, marketID, outcome)
}

package markets

import (
	"context"
	"strings"

	"socialpredict/internal/domain/boundary"
)

// ProjectProbability projects what the probability would be after a hypothetical bet.
func (s *Service) ProjectProbability(ctx context.Context, req ProbabilityProjectionRequest) (*ProbabilityProjection, error) {
	if err := s.probabilityValidator.ValidateRequest(req); err != nil {
		return nil, err
	}

	market, err := s.repo.GetByID(ctx, req.MarketID)
	if err != nil {
		return nil, err
	}
	if market == nil {
		return nil, ErrMarketNotFound
	}

	if err := s.probabilityValidator.ValidateMarket(market, s.clock.Now()); err != nil {
		return nil, err
	}

	bets, err := s.repo.ListBetsForMarket(ctx, req.MarketID)
	if err != nil {
		return nil, err
	}

	boundaryBets := convertToBoundaryBets(bets)
	probabilityTrack := s.probabilityEngine.Calculate(market.CreatedAt, boundaryBets)

	currentProbability := 0.5
	if len(probabilityTrack) > 0 {
		currentProbability = probabilityTrack[len(probabilityTrack)-1].Probability
	}

	newBet := boundary.Bet{
		Username: "preview",
		MarketID: uint(market.ID),
		Amount:   req.Amount,
		Outcome:  normalizeOutcome(req.Outcome),
		PlacedAt: s.clock.Now(),
	}

	projection := s.probabilityEngine.Project(market.CreatedAt, boundaryBets, newBet)

	result := &ProbabilityProjection{
		CurrentProbability: currentProbability,
	}
	result.ProjectedProbability = projection.ProjectedProbability

	return result, nil
}

func normalizeOutcome(outcome string) string {
	switch strings.ToUpper(strings.TrimSpace(outcome)) {
	case "YES":
		return "YES"
	case "NO":
		return "NO"
	default:
		return ""
	}
}

package marketshandlers

import (
	"fmt"
	"strings"
)

// normalizeStatusParam converts arbitrary status input to the canonical value understood by the domain layer.
// Returns "" when no filter should be applied (empty/all), otherwise one of active|closed|resolved.
func normalizeStatusParam(raw string) (string, error) {
	value := strings.TrimSpace(raw)
	if value == "" {
		return "", nil
	}

	value = strings.ToLower(value)
	switch value {
	case "active", "closed", "resolved":
		return value, nil
	case "all":
		return "", nil
	default:
		return "", fmt.Errorf("invalid status %q", raw)
	}
}

