package markets

import (
	"testing"
	"time"

	"socialpredict/models"
)

func TestMapModelBetsToBoundaryPreservesBetFields(t *testing.T) {
	now := time.Unix(1700000000, 0).UTC()
	dbBets := []models.Bet{{
		ID:       9,
		Username: "alice",
		MarketID: 7,
		Amount:   25,
		Outcome:  "YES",
		PlacedAt: now,
	}}

	got := mapModelBetsToBoundary(dbBets)
	if len(got) != 1 {
		t.Fatalf("expected 1 bet, got %d", len(got))
	}
	if got[0].ID != 9 || got[0].Username != "alice" || got[0].MarketID != 7 || got[0].Amount != 25 || got[0].Outcome != "YES" || !got[0].PlacedAt.Equal(now) {
		t.Fatalf("unexpected mapped bet: %#v", got[0])
	}
}
package markets

import (
	"context"
	"errors"
	"testing"
	"time"

	dmarkets "socialpredict/internal/domain/markets"
	"socialpredict/models"
	"socialpredict/models/modelstesting"
)

func TestGormRepositoryCreateAndGetByID(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	repo := NewGormRepository(db)
	ctx := context.Background()

	now := time.Now().UTC().Truncate(time.Second)
	market := &dmarkets.Market{
		QuestionTitle:           "Test market",
		Description:             "Description",
		OutcomeType:             "BINARY",
		ResolutionDateTime:      now.Add(24 * time.Hour),
		FinalResolutionDateTime: now.Add(48 * time.Hour),
		ResolutionResult:        "",
		CreatorUsername:         "creator",
		YesLabel:                "YES",
		NoLabel:                 "NO",
		Status:                  "active",
		CreatedAt:               now,
		UpdatedAt:               now,
		InitialProbability:      0.5,
		UTCOffset:               -5,
	}

	if err := repo.Create(ctx, market); err != nil {
		t.Fatalf("Create returned error: %v", err)
	}
	if market.ID == 0 {
		t.Fatalf("expected market ID to be set")
	}

	got, err := repo.GetByID(ctx, market.ID)
	if err != nil {
		t.Fatalf("GetByID returned error: %v", err)
	}
	if got.QuestionTitle != market.QuestionTitle || got.CreatorUsername != market.CreatorUsername || got.YesLabel != "YES" || got.InitialProbability != 0.5 {
		t.Fatalf("unexpected market data: %+v", got)
	}

	if _, err := repo.GetByID(ctx, market.ID+999); !errors.Is(err, dmarkets.ErrMarketNotFound) {
		t.Fatalf("expected ErrMarketNotFound, got %v", err)
	}
}

func TestGormRepositoryUpdateLabels(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	repo := NewGormRepository(db)
	ctx := context.Background()

	seed := modelstesting.GenerateMarket(100, "creator")
	if err := db.Create(&seed).Error; err != nil {
		t.Fatalf("seed market: %v", err)
	}

	if err := repo.UpdateLabels(ctx, seed.ID, "Moon", "Sun"); err != nil {
		t.Fatalf("UpdateLabels returned error: %v", err)
	}

	var refreshed models.Market
	if err := db.First(&refreshed, seed.ID).Error; err != nil {
		t.Fatalf("reload market: %v", err)
	}
	if refreshed.YesLabel != "Moon" || refreshed.NoLabel != "Sun" {
		t.Fatalf("labels not updated: %+v", refreshed)
	}

	if err := repo.UpdateLabels(ctx, seed.ID+1, "A", "B"); !errors.Is(err, dmarkets.ErrMarketNotFound) {
		t.Fatalf("expected ErrMarketNotFound for missing market, got %v", err)
	}
}

func TestGormRepositoryListBetsForMarket(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	repo := NewGormRepository(db)
	ctx := context.Background()

	creator := modelstesting.GenerateUser("creator", 1000)
	bettor := modelstesting.GenerateUser("bettor", 1000)
	if err := db.Create(&creator).Error; err != nil {
		t.Fatalf("seed creator: %v", err)
	}
	if err := db.Create(&bettor).Error; err != nil {
		t.Fatalf("seed bettor: %v", err)
	}

	market := modelstesting.GenerateMarket(200, creator.Username)
	if err := db.Create(&market).Error; err != nil {
		t.Fatalf("seed market: %v", err)
	}

	first := models.Bet{
		Username: "bettor",
		MarketID: uint(market.ID),
		Amount:   10,
		Outcome:  "YES",
		PlacedAt: time.Now().Add(-2 * time.Minute),
	}
	second := models.Bet{
		Username: "bettor",
		MarketID: uint(market.ID),
		Amount:   15,
		Outcome:  "NO",
		PlacedAt: time.Now().Add(-1 * time.Minute),
	}
	if err := db.Create(&first).Error; err != nil {
		t.Fatalf("insert first bet: %v", err)
	}
	if err := db.Create(&second).Error; err != nil {
		t.Fatalf("insert second bet: %v", err)
	}

	bets, err := repo.ListBetsForMarket(ctx, market.ID)
	if err != nil {
		t.Fatalf("ListBetsForMarket returned error: %v", err)
	}

	if len(bets) != 2 {
		t.Fatalf("expected 2 bets, got %d", len(bets))
	}
	if bets[0].Username != "bettor" || bets[0].Amount != 10 || bets[0].Outcome != "YES" {
		t.Fatalf("unexpected first bet: %+v", bets[0])
	}
	if !bets[0].PlacedAt.Before(bets[1].PlacedAt) {
		t.Fatalf("bets not ordered ascending by PlacedAt")
	}
}

	for _, pos := range positions {
		out = append(out, &dmarkets.UserPosition{
			Username:         pos.Username,
			MarketID:         int64(pos.MarketID),
			YesSharesOwned:   pos.YesSharesOwned,
			NoSharesOwned:    pos.NoSharesOwned,
			Value:            pos.Value,
			TotalSpent:       pos.TotalSpent,
			TotalSpentInPlay: pos.TotalSpentInPlay,
			IsResolved:       pos.IsResolved,
			ResolutionResult: pos.ResolutionResult,
		})
	}
	return out, nil
}

// Delete removes a market from the database
func (r *GormRepository) Delete(ctx context.Context, id int64) error {
	result := r.db.WithContext(ctx).Delete(&models.Market{}, id)
	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dmarkets.ErrMarketNotFound
	}

	return nil
}

// ResolveMarket marks a market as resolved with the given resolution
func (r *GormRepository) ResolveMarket(ctx context.Context, id int64, resolution string) error {
	result := r.db.WithContext(ctx).Model(&models.Market{}).
		Where("id = ?", id).
		Updates(map[string]any{
			"is_resolved":                true,
			"resolution_result":          resolution,
			"final_resolution_date_time": time.Now(),
			"updated_at":                 time.Now(),
		})

	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dmarkets.ErrMarketNotFound
	}

	return nil
}

// ListBetsForMarket returns all bets for the specified market ordered by placement time.
func (r *GormRepository) ListBetsForMarket(ctx context.Context, marketID int64) ([]*dmarkets.Bet, error) {
	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}

	result := make([]*dmarkets.Bet, len(bets))
	for i := range bets {
		result[i] = &dmarkets.Bet{
			ID:        bets[i].ID,
			Username:  bets[i].Username,
			MarketID:  bets[i].MarketID,
			Amount:    bets[i].Amount,
			Outcome:   bets[i].Outcome,
			PlacedAt:  bets[i].PlacedAt,
			CreatedAt: bets[i].CreatedAt,
		}
	}
	return result, nil
}

// CalculatePayoutPositions computes the resolved valuations for a market's participants.
func (r *GormRepository) CalculatePayoutPositions(ctx context.Context, marketID int64) ([]*dmarkets.PayoutPosition, error) {
	snapshot, bets, err := r.loadMarketData(ctx, marketID)
	if err != nil {
		return nil, err
	}

	positions, err := positionsmath.CalculateMarketPositions_WPAM_DBPM(snapshot, bets)
	if err != nil {
		return nil, err
	}

	result := make([]*dmarkets.PayoutPosition, 0, len(positions))
	for _, pos := range positions {
		result = append(result, &dmarkets.PayoutPosition{
			Username: pos.Username,
			Value:    pos.Value,
		})
	}
	return result, nil
}

func (r *GormRepository) loadMarketData(ctx context.Context, marketID int64) (positionsmath.MarketSnapshot, []boundary.Bet, error) {
	var market models.Market
	if err := r.db.WithContext(ctx).First(&market, marketID).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return positionsmath.MarketSnapshot{}, nil, dmarkets.ErrMarketNotFound
		}
		return positionsmath.MarketSnapshot{}, nil, err
	}

	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return positionsmath.MarketSnapshot{}, nil, err
	}

	snapshot := positionsmath.MarketSnapshot{
		ID:               int64(market.ID),
		CreatedAt:        market.CreatedAt,
		IsResolved:       market.IsResolved,
		ResolutionResult: market.ResolutionResult,
	}

	return snapshot, mapModelBetsToBoundary(bets), nil
}

func mapModelBetsToBoundary(dbBets []models.Bet) []boundary.Bet {
	bets := make([]boundary.Bet, len(dbBets))
	for i, bet := range dbBets {
		bets[i] = boundary.Bet{
			ID:        uint(bet.ID),
			Username:  bet.Username,
			MarketID:  bet.MarketID,
			Amount:    bet.Amount,
			Outcome:   bet.Outcome,
			PlacedAt:  bet.PlacedAt,
			CreatedAt: bet.CreatedAt,
		}
	}
	return bets
}

// domainToModel converts a domain market to a GORM model
func (r *GormRepository) domainToModel(market *dmarkets.Market) models.Market {
	return models.Market{
		ID:                      market.ID,
		QuestionTitle:           market.QuestionTitle,
		Description:             market.Description,
		OutcomeType:             market.OutcomeType,
		ResolutionDateTime:      market.ResolutionDateTime,
		FinalResolutionDateTime: market.FinalResolutionDateTime,
		ResolutionResult:        market.ResolutionResult,
		CreatorUsername:         market.CreatorUsername,
		YesLabel:                market.YesLabel,
		NoLabel:                 market.NoLabel,
		UTCOffset:               market.UTCOffset,
		IsResolved:              market.Status == "resolved",
		InitialProbability:      market.InitialProbability,
	}
}

